  assign ser_rkmsb = even ? ser_tkmsb : ser_rkmsb_odd; 
  assign ser_rklsb = even ? ser_tklsb : ser_rklsb_odd; 
  assign ser_r = error ^ (even ? ser_t : ser_r_odd); 
 endmodule

