    reset,
    enb,
    processDataIn,
    validIn,
    dumping,
    outputData,
    processData,
    dumpOrValid
  );

  input  clk;
  input  reset;
  input  enb;
  input  processDataIn;
  input  validIn;
  input  dumping;
  input  outputData;

  output processData;
  output dumpOrValid;

  wire processNull;
  reg  validREG;
  wire validOrDumping;
