module rtlpp_09102 (
    address,
    byteenable,
    chipselect,
    clk,
    clken,
    debugaccess,
    reset,
    write,
    writedata,
    readdata
);

  parameter INIT_FILE = "ddr2_v11_0_p0_sequencer_rom.hex";

  output  [31:0] readdata;
  input   [11:0] address;
  input   [3:0] byteenable;
  input          chipselect;
  input          clk;
  input          clken;
  input          debugaccess;
  input          reset;
  input          write;
  input   [31:0] writedata;

  reg [31:0] memory [4095:0];
  reg [31:0] readdata;
  wire       wren;
  integer    i;

  assign wren = chipselect & write & debugaccess;

  initial begin
    $readmemh(INIT_FILE, memory);
  end

  always @(posedge clk) begin
    if (reset) begin
      readdata <= 32'b0;
    end else if (clken) begin
      if (wren) begin
        if (byteenable[0]) memory[address][ 7: 0] <= writedata[ 7: 0];
        if (byteenable[1]) memory[address][15: 8] <= writedata[15: 8];
        if (byteenable[2]) memory[address][23:16] <= writedata[23:16];
        if (byteenable[3]) memory[address][31:24] <= writedata[31:24];
        readdata <= memory[address];
      end else begin
        readdata <= memory[address];
      end
    end
  end

endmodule

