    parameter RCA_WIDTH = 1;
    parameter RED_COLUMNS = 2;

    output [127:0] Q;
    input CLK;
    input CEN;
    input WEN;
    input [10:0] A;
    input [127:0] D;
    input [2:0] EMA;

    reg [BITS+RED_COLUMNS-1:0] mem [0:WORD_DEPTH-1];
    reg [BITS+RED_COLUMNS-1:0] rows [(MUX*4)-1:0];   

