  6'h24: begin ALU_Control=3'b111; 
  ALUSrc_B=1; RegWrite=1; end 
  6'h08: begin ALU_Control=3'b010; 
  ALUSrc_B=1; RegWrite=1; end 
  6'h0c: begin ALU_Control=3'b000; 
  ALUSrc_B=1; RegWrite=1; end 
  6'h0d: begin ALU_Control=3'b001; 
  ALUSrc_B=1; RegWrite=1;end 
