    input [7:0] I0,
    input [7:0] I1,
    input CIN,
    output [7:0] O,
    output COUT
);
  wire FullAdder_inst0_O;
  wire FullAdder_inst0_COUT;
  wire FullAdder_inst1_O;
  wire FullAdder_inst1_COUT;
  wire FullAdder_inst2_O;
