  wire FullAdder_inst7_O;
  wire FullAdder_inst7_COUT;
  FullAdder FullAdder_inst0 (
      .I0(I0[0]),
      .I1(I1[0]),
      .CIN(CIN),
      .O(FullAdder_inst0_O),
      .COUT(FullAdder_inst0_COUT)
  );
  FullAdder FullAdder_inst1 (
      .I0(I0[1]),
      .I1(I1[1]),
      .CIN(FullAdder_inst0_COUT),
      .O(FullAdder_inst1_O),
      .COUT(FullAdder_inst1_COUT)
  );
  FullAdder FullAdder_inst2 (
      .I0(I0[2]),
      .I1(I1[2]),
      .CIN(FullAdder_inst1_COUT),
      .O(FullAdder_inst2_O),
      .COUT(FullAdder_inst2_COUT)
  );
  FullAdder FullAdder_inst3 (
      .I0(I0[3]),
      .I1(I1[3]),
      .CIN(FullAdder_inst2_COUT),
      .O(FullAdder_inst3_O),
      .COUT(FullAdder_inst3_COUT)
  );
  FullAdder FullAdder_inst4 (
      .I0(I0[4]),
      .I1(I1[4]),
      .CIN(FullAdder_inst3_COUT),
      .O(FullAdder_inst4_O),
      .COUT(FullAdder_inst4_COUT)
  );
  FullAdder FullAdder_inst5 (
      .I0(I0[5]),
      .I1(I1[5]),
      .CIN(FullAdder_inst4_COUT),
      .O(FullAdder_inst5_O),
      .COUT(FullAdder_inst5_COUT)
  );
  FullAdder FullAdder_inst6 (
      .I0(I0[6]),
      .I1(I1[6]),
      .CIN(FullAdder_inst5_COUT),
      .O(FullAdder_inst6_O),
      .COUT(FullAdder_inst6_COUT)
  );
  FullAdder FullAdder_inst7 (
      .I0(I0[7]),
      .I1(I1[7]),
      .CIN(FullAdder_inst6_COUT),
      .O(FullAdder_inst7_O),
      .COUT(FullAdder_inst7_COUT)
  );
  assign O = {
    FullAdder_inst7_O,
    FullAdder_inst6_O,
    FullAdder_inst5_O,
    FullAdder_inst4_O,
    FullAdder_inst3_O,
    FullAdder_inst2_O,
    FullAdder_inst1_O,
    FullAdder_inst0_O
  };
  assign COUT = FullAdder_inst7_COUT;
endmodule

