module autovcoder_089994 (
    CLOCK_50,
    CLOCK2_50,
    KEY,
    FPGA_I2C_SCLK,
    FPGA_I2C_SDAT,
    AUD_XCK,
    AUD_DACLRCK,
    AUD_ADCLRCK,
    AUD_BCLK,
    AUD_ADCDAT,
    AUD_DACDAT
);

  input CLOCK_50, CLOCK2_50;
  input [0:0] KEY;
  // I2C Audio/Video config interface
  output FPGA_I2C_SCLK;
  inout FPGA_I2C_SDAT;
  // Audio CODEC
  output AUD_XCK;
  input AUD_DACLRCK, AUD_ADCLRCK, AUD_BCLK;
  input AUD_ADCDAT;
  output AUD_DACDAT;

  // Local wires.
  wire read_ready, write_ready, read, write;
  wire [23:0] readdata_left, readdata_right;
  wire [23:0] writedata_left, writedata_right;
  wire reset = ~KEY[0];
  wire enable = 1'b1;

  /////////////////////////////////
  // Your code goes here 
  /////////////////////////////////

  wire signed [23:0] filter_out_left, filter_out_right;

  assign writedata_left = write_ready ? filter_out_left : writedata_left;
  assign writedata_right = write_ready ? filter_out_right : writedata_right;
  assign read = read_ready;
  assign write = write_ready;

  filter FILTER_LEFT (
      CLOCK_50,
      readdata_left,
      filter_out_left,
      read_ready
  );
  filter FILTER_RIGHT (
      CLOCK_50,
      readdata_right,
      filter_out_right,
      read_ready
  );

  /////////////////////////////////////////////////////////////////////////////////
  // Audio CODEC interface. 
  //
  // The interface consists of the following wires:
  // read_ready, write_ready - CODEC ready for read/write operation 
  // readdata_left, readdata_right - left and right channel data from the CODEC
  // read - send data from the CODEC (both channels)
  // writedata_left, writedata_right - left and right channel data to the CODEC
  // write - send data to the CODEC (both channels)
  // AUD_* - should connect to top-level entity I/O of the same name.
  //         These signals go directly to the Audio CODEC
  // I2C_* - should connect to top-level entity I/O of the same name.
  //         These signals go directly to the Audio/Video Config module
  /////////////////////////////////////////////////////////////////////////////////
  clock_generator my_clock_gen (
      // inputs
      CLOCK2_50,
      reset,

      // outputs
      AUD_XCK
  );

  audio_and_video_config cfg (
      // Inputs
      CLOCK_50,
      reset,

      // Bidirectionals
      FPGA_I2C_SDAT,
      FPGA_I2C_SCLK
