module FA(a, b, cin, sum, cout);

    input a, b, cin;
    output sum, cout;

    assign sum = a ^ b ^ cin;
    assign cout = (a & b) | (b & cin) | (cin & a);

endmodule

module RCA4(output [3:0] sum, output cout, input [3:0] a, b, input cin);

  wire [3:0] c;

  FA fa0(sum[0], c[1], a[0], b[0], cin);
  FA fa1(sum[1], c[2], a[1], b[1], c[1]);
  FA fa2(sum[2], c[3], a[2], b[2], c[2]);
  FA fa3(sum[3], cout, a[3], b[3], c[3]);

endmodule

module SkipLogic(output cin_next, input [3:0] a, b, input cin, cout);

  wire p0, p1, p2, p3, P, e;

  or (p0, a[0], b[0]);
  or (p1, a[1], b[1]);
  or (p2, a[2], b[2]);
  or (p3, a[3], b[3]);

  and (P, p0, p1, p2, p3);
  and (e, P, cin);

  or (cin_next, e, cout);

endmodule

