  response_fifo_empty,
  done_strobe,
  actual_bytes_transferred,
  error,
  early_termination,
  transfer_complete_IRQ_mask,
  error_IRQ_mask,
  early_termination_IRQ_mask,
  descriptor_buffer_full
);

  parameter RESPONSE_PORT = 0;   
  parameter FIFO_DEPTH = 256;    
  parameter FIFO_DEPTH_LOG2 = 8;
  localparam FIFO_WIDTH = (RESPONSE_PORT == 0)? 41 : 51;  

  input clk;
  input reset;

  output [31:0] mm_response_readdata;
  input mm_response_read;
  input mm_response_address;  
  input [3:0] mm_response_byteenable;
  output mm_response_waitrequest;

  output [255:0] src_response_data;  
  output src_response_valid;
  input src_response_ready;

  input sw_reset;
  output [15:0] response_watermark;
  output response_fifo_full;
  output response_fifo_empty;
  input done_strobe;
  input [31:0] actual_bytes_transferred;
  input [7:0] error;
  input early_termination;

  input transfer_complete_IRQ_mask;
  input [7:0] error_IRQ_mask;
  input early_termination_IRQ_mask;
  input descriptor_buffer_full;  

  wire [FIFO_DEPTH_LOG2-1:0] fifo_used;
  wire fifo_full;
  wire fifo_empty;
  wire fifo_read;
  wire [FIFO_WIDTH-1:0] fifo_input;
  wire [FIFO_WIDTH-1:0] fifo_output;

  reg [FIFO_DEPTH_LOG2-1:0] fifo_used_s;
  reg fifo_full_s;
  reg fifo_empty_s;
  reg [FIFO_WIDTH-1:0] fifo_mem [0:FIFO_DEPTH-1];
  reg [FIFO_WIDTH-1:0] fifo_output_s;
  integer wr_pointer, rd_pointer;

  initial begin
    wr_pointer = 0;
    rd_pointer = 0;
    fifo_full_s = 0;
    fifo_empty_s = 1;
    fifo_used_s = 0;
  end

  always @(posedge clk or posedge reset) begin
    if (reset || sw_reset) begin
      wr_pointer <= 0;
      rd_pointer <= 0;
      fifo_full_s <= 0;
      fifo_empty_s <= 1;
      fifo_used_s <= 0;
    end else begin
      if (done_strobe && !fifo_full_s) begin
        fifo_mem[wr_pointer] <= fifo_input;
        wr_pointer <= wr_pointer + 1;
      end

      if (fifo_read && !fifo_empty_s) begin
        fifo_output_s <= fifo_mem[rd_pointer];
        rd_pointer <= rd_pointer + 1;
      end

      fifo_used_s <= wr_pointer - rd_pointer;
      fifo_full_s <= (fifo_used_s == FIFO_DEPTH);
      fifo_empty_s <= (fifo_used_s == 0);
    end
  end

  assign fifo_input = (RESPONSE_PORT == 0) ? {early_termination, error, actual_bytes_transferred} :
                      {early_termination_IRQ_mask, error_IRQ_mask, transfer_complete_IRQ_mask, early_termination, error, actual_bytes_transferred};

  assign fifo_read = (RESPONSE_PORT == 0) ? (mm_response_read && !fifo_empty && mm_response_address && mm_response_byteenable[3]) :
                     (!fifo_empty && src_response_ready);

  assign mm_response_readdata = (RESPONSE_PORT == 0) ? (mm_response_address ? {{23{1'b0}}, fifo_output_s[40:32]} : fifo_output_s[31:0]) : 0;
  assign mm_response_waitrequest = (RESPONSE_PORT == 0) ? fifo_empty : 0;
  assign response_watermark = {{(16-(FIFO_DEPTH_LOG2+1)){1'b0}}, fifo_full_s, fifo_used_s};  
  assign response_fifo_full = fifo_full_s;
  assign response_fifo_empty = fifo_empty_s;
  assign src_response_data = (RESPONSE_PORT == 1) ? {{204{1'b0}}, descriptor_buffer_full, fifo_output_s} : 0;
  assign src_response_valid = (RESPONSE_PORT == 1) ? !fifo_empty_s : 0;

endmodule

