				busy_w   = 1'b0; 
				valid_w	= 1'b0; 
				result_w = 16'd0; 
				counter 	= 16'd0; 
				state 	= IDLE;
		end else begin		
			case (state)
			IDLE: begin
				cnv_w		= 1'b0; 
				clk_en	= 1'b0; 
				busy_w   = 1'b0; 
				valid_w	= 1'b0; 
				result_w = 16'd0;
				counter =  16'd0;
				if (CNV_START == 1'b1)	begin
					counter <= 16'd64; 
					state <= CONVERT;
				end else	state = IDLE;
			end

			CONVERT: begin
				cnv_w = 1'b1; 
				busy_w = 1'b1; 
				if (counter == 16'd0) begin  
					counter <= 16'd31;	
					cnv_w = 1'b0; 		
					state <= READ_OUT;
				end else begin 
					state = CONVERT;
					counter = counter - 1'b1; 
				end
			end

			READ_OUT: begin
				if (counter == 16'd31) begin
					result_w[15] = SDO;  
					counter = counter - 1'b1; 
					clk_en = 1'b1;
					state = READ_OUT;
				end else if ( (counter == 16'd30) || (counter == 16'd28) || (counter == 16'd26) || (counter == 16'd24) || (counter == 16'd22) || (counter == 16'd20) || (counter == 16'd18) || (counter == 16'd16) || (counter == 16'd14) || (counter == 16'd12) || (counter == 16'd10) || (counter == 16'd8) || (counter == 16'd6) || (counter == 16'd4) || (counter == 16'd2)) begin
					clk_en = 1'b1;
					result_w[counter >> 1] = SDO;
					counter = counter - 1'b1; 
					state = READ_OUT;
				end else if (counter == 16'd0) begin
					result_w[counter] = SDO;  
					counter <= 16'd35; 
					state = VALID_F;
				end else
					counter = counter - 1'b1; 
			end

			VALID_F: begin
				valid_w = 1'b1;
				state = WAIT;
			end

			WAIT: begin
				busy_w 	= 1'b0; 
				clk_en	= 1'b0;	
				valid_w = 1'b0; 
				if (counter == 16'd0) begin
					state = IDLE;
				end else begin 
					state = WAIT;
					counter = counter - 1'b1; 
				end
			end

			default: state <= IDLE;
			endcase
		end
	end

	assign BUSY = busy_w;
	assign CNV = cnv_w;
	assign SDI = 1'b1; 
	assign RESULT = result_w;
	assign VALID = valid_w;

	always @(posedge CLK) begin
		SCK = (!SCK) & clk_en;
	end

endmodule

