  end 
  PRE_READ: begin 
  state <= READ_READY; 
  end 
  READ_READY: begin 
  address_o <= address_o + 1'b1; 
  state <= READ_CAPTURE; 
  end 
  READ_CAPTURE: begin 
  rd_buffer <= q_i; 
  state <= WAIT_READ; 
  end 
  WAIT_READ: begin 
  if( abort_sig ) 
  begin 
  state <= IDLE; 
  fsm_abort <= ~fsm_abort; 
  end else 
  if( (A_i == 4'd8) && rd_i ) state <= READ_READY; 
  end 
