      r_awaddr <= 0;
      r_awprot <= 0;
      r_awvalid <= 0;
      r_wdata <= 0;
      r_wstrb <= 0;
      r_wvalid <= 0;
      r_bready <= 0;
      r_araddr <= 0;
      r_arprot <= 0;
      r_arvalid <= 0;
