files.autovcoder_003504.v:
module autovcoder_003504 #(
    parameter DATA_TYPE = 32,
    parameter NUM_IN = 4,
    parameter SEL_IN = 2
) (
    clk,
    rst,

    i_valid,  // valid data signal
    i_data_bus,  // input data bus coming into adder switch

    // reconfigurable control signal
    i_add_en,  // add enable
    i_cmd,  // command forward
    i_sel,  // reduction mux select bits

    o_vn,  // vn output 
    o_vn_valid,  // vn output valid

    o_adder  // output of the adders (can be sum or forwarding)
);

  parameter NUM_OUT = 2;

  input clk;
  input rst;

  input i_valid;  // input data valid
  input [(DATA_TYPE*NUM_IN)-1:0] i_data_bus;  // input data bus to select from

  input i_add_en;
  input [2:0] i_cmd;  // Adder functionality bits
  // 000 --> NA
  // 001 --> forward both original data (left to left, right to right) -  REMOVED bypass regardless
  // 010 --> add data and forward to both paths
  // 011 --> send left input as VN output and forward right input
  // 100 --> send right input as VN output and forward left input
  // 101 --> send both inputs as VN outputs

  input [SEL_IN-1:0] i_sel;  // select bits for the reduction mux

  output reg [(2*DATA_TYPE)-1:0] o_vn;  // vn output
  output reg [1:0] o_vn_valid;  // vn output valid

  output reg [(DATA_TYPE*NUM_OUT)-1:0] o_adder; // output of the adders (can be sum or forwarding), upper half --> left, lower half --> right


  wire [(2 * DATA_TYPE)-1:0] w_sel_data;  // selected data from reduction mux

  wire [DATA_TYPE-1:0] w_O;  // output of adder

  reg [(DATA_TYPE*NUM_OUT)-1:0] r_adder;

  reg r_add_en;
  reg [(2*DATA_TYPE)-1:0] r_vn;
  reg [1:0] r_vn_valid;


  // generate mux logic to select input data bus values to the two inputs of the adder
  reduction_mux #(
      .W(DATA_TYPE),
      .NUM_IN(NUM_IN),
      .SEL_IN(SEL_IN),
      .NUM_OUT(NUM_OUT)
  ) my_reduction_mux (
      .i_data(i_data_bus),
      .i_sel (i_sel),
      .o_data(w_sel_data)
  );

  // Reconfigurable control logic select
  always @(posedge clk) begin
    if (rst == 1'b1) begin
      r_adder <= 'b0;
      r_vn <= 'b0;
      r_vn_valid <= 'b0;
    end else begin
      if (i_valid == 1'b1) begin
        case (i_cmd)
          3'b000: begin
            // NA
            r_vn_valid <= 2'b00;
          end
          3'b001: begin
            //forward both original data (left to left, right to right)
            r_adder <= w_sel_data;
            r_vn_valid <= 2'b00;
          end
          3'b010: begin
            // NA
            r_vn_valid <= 2'b00;
          end
          3'b011: begin
            // send left input as VN output and forward right input
            r_adder[2*DATA_TYPE-1:DATA_TYPE] <= w_sel_data[2*DATA_TYPE-1:DATA_TYPE];
            r_vn[DATA_TYPE-1:0] <= i_data_bus[DATA_TYPE-1:0];
            r_vn_valid <= 2'b01;
          end
          3'b100: begin
            // send right input as VN output and forward left input
            r_adder[DATA_TYPE-1:0] <= w_sel_data[DATA_TYPE-1:0];
            r_vn[2*DATA_TYPE-1:DATA_TYPE] <= i_data_bus[(DATA_TYPE*NUM_IN)-1:DATA_TYPE*(NUM_IN-1)];
            r_vn_valid <= 2'b10;
          end
          3'b101: begin
            // send both inputs as VN outputs
            r_vn <= w_sel_data;
            r_vn_valid <= 2'b11;
          end
          default: begin
            // nothing happens, adder inactive 
            r_vn_valid <= 2'b00;
          end
        endcase
      end
    end
  end

  // flop i_cmd for timing logic
  always @(posedge clk) begin
    if (rst == 1'b1) begin
      r_add_en <= 'b0;
    end else begin
      r_add_en <= i_add_en;
    end
  end


  // Flop forwarding values for timing consistency with o_adder timing logic
  always @(*) begin
    if (rst == 1'b1) begin
      o_adder <= 'd0;
      o_vn <= 'd0;
      o_vn_valid <= 'd0;
    end else begin
      if (r_add_en == 1'b0) begin
        o_adder <= r_adder;
      end else begin
        o_adder <= {w_O, w_O};
      end
      o_vn <= r_vn;
      o_vn_valid <= r_vn_valid;
    end
  end

  // instantiate FP32 adder
  adder32 my_adder (
      .clk(clk),
      .rst(rst),
      .A  (w_sel_data[DATA_TYPE+:DATA_TYPE]),
      .B  (w_sel_data[0+:DATA_TYPE]),
      .O  (w_O)
  );

endmodule

files.conformal_rtl_autovcoder_003504.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

files.rtlpp_05013.v:
module rtlpp_05013(
    input wire  clk, 
    input wire resetq, 
    input wire rx, 
    output wire tx, 
    input wire rd, 
    input wire wr, 
    output wire valid, 
    output wire busy, 
    input wire [7:0] tx_data, 
    output wire [7:0] rx_data 
    );

`define CLKFREQ   30000000    
`define BAUD      115200

localparam CLOCK_DIVIDE = `CLKFREQ / (`BAUD * 4);

parameter RX_IDLE = 0;
parameter RX_CHECK_START = 1;
parameter RX_READ_BITS = 2;
parameter RX_CHECK_STOP = 3;
parameter RX_DELAY_RESTART = 4;
parameter RX_ERROR = 5;
parameter RX_RECEIVED = 6;

parameter TX_IDLE = 0;
parameter TX_SENDING = 1;
parameter TX_DELAY_RESTART = 2;

reg [10:0] rx_clk_divider = CLOCK_DIVIDE;
reg [10:0] tx_clk_divider = CLOCK_DIVIDE;

reg [2:0] recv_state = RX_IDLE;
reg [5:0] rx_countdown;
reg [3:0] rx_bits_remaining;
reg [7:0] rx_data_;

reg tx_out = 1'b1;
reg [1:0] tx_state = TX_IDLE;
reg [5:0] tx_countdown;
reg [3:0] tx_bits_remaining;
reg [7:0] tx_data_;

assign valid = (recv_state == RX_RECEIVED);
assign rx_data = rx_data_;
assign tx = tx_out;
assign busy = (tx_state != TX_IDLE);

always @(posedge clk) begin
  if (!resetq) begin
    recv_state <= RX_IDLE;
    tx_state <= TX_IDLE;
  end else begin
    rx_clk_divider <= rx_clk_divider - 11'd1;
    if (rx_clk_divider == 0) begin
      rx_clk_divider <= CLOCK_DIVIDE;
      rx_countdown <= rx_countdown - 6'd1;
    end
    tx_clk_divider <= tx_clk_divider - 11'd1;
    if (tx_clk_divider == 0) begin
      tx_clk_divider <= CLOCK_DIVIDE;
      tx_countdown <= tx_countdown - 6'd1;
    end

    case (recv_state)
      RX_IDLE: begin
        if (!rx) begin
          rx_clk_divider <= CLOCK_DIVIDE;
          rx_countdown <= 6'd2;
          recv_state <= RX_CHECK_START;
        end
      end

      RX_CHECK_START: begin
        if (rx_countdown == 0) begin
          if (!rx) begin
            rx_countdown <= 6'd4;
            rx_bits_remaining <= 4'd8;
            recv_state <= RX_READ_BITS;
          end else begin
            recv_state <= RX_ERROR;
          end
        end
      end

      RX_READ_BITS: begin
        if (rx_countdown == 0) begin
          rx_data_ <= {rx, rx_data_[7:1]};
          rx_countdown <= 6'd4;
          rx_bits_remaining <= rx_bits_remaining - 4'd1;
          recv_state <= (rx_bits_remaining ? RX_READ_BITS : RX_CHECK_STOP);
        end
      end

      RX_CHECK_STOP: begin
        if (rx_countdown == 0) begin
          recv_state <= (rx ? RX_RECEIVED : RX_ERROR);
        end
      end

      RX_DELAY_RESTART: begin
        recv_state <= (rx_countdown ? RX_DELAY_RESTART : RX_IDLE);
      end

      RX_ERROR: begin
        rx_countdown <= 6'd8;
        recv_state <= RX_DELAY_RESTART;
      end

      RX_RECEIVED: begin
        if (rd) begin
          recv_state <= RX_IDLE;
        end
      end
    endcase

    case (tx_state)
      TX_IDLE: begin
        if (wr) begin
          tx_data_ <= tx_data;
          tx_clk_divider <= CLOCK_DIVIDE;
          tx_countdown <= 6'd4;
          tx_out <= 1'b0;
          tx_bits_remaining <= 4'd8;
          tx_state <= TX_SENDING;
        end
      end

      TX_SENDING: begin
        if (tx_countdown == 0) begin
          if (tx_bits_remaining) begin
            tx_bits_remaining <= tx_bits_remaining - 4'd1;
            tx_out <= tx_data_[0];
            tx_data_ <= {1'b0, tx_data_[7:1]};
            tx_countdown <= 6'd4;
            tx_state <= TX_SENDING;
          end else begin
            tx_out <= 1'b1;
            tx_countdown <= 6'd8;
            tx_state <= TX_DELAY_RESTART;
          end
        end
      end

      TX_DELAY_RESTART: begin
        tx_state <= (tx_countdown ? TX_DELAY_RESTART : TX_IDLE);
      end
    endcase
  end
end

endmodule

