module rtlpp_05013(
    input wire  clk, 
    input wire resetq, 
    input wire rx, 
    output wire tx, 
    input wire rd, 
    input wire wr, 
    output wire valid, 
    output wire busy, 
    input wire [7:0] tx_data, 
    output wire [7:0] rx_data 
    );

`define CLKFREQ   30000000    
`define BAUD      115200

localparam CLOCK_DIVIDE = `CLKFREQ / (`BAUD * 4);

parameter RX_IDLE = 0;
parameter RX_CHECK_START = 1;
parameter RX_READ_BITS = 2;
parameter RX_CHECK_STOP = 3;
parameter RX_DELAY_RESTART = 4;
parameter RX_ERROR = 5;
parameter RX_RECEIVED = 6;

parameter TX_IDLE = 0;
parameter TX_SENDING = 1;
parameter TX_DELAY_RESTART = 2;

reg [10:0] rx_clk_divider = CLOCK_DIVIDE;
reg [10:0] tx_clk_divider = CLOCK_DIVIDE;

reg [2:0] recv_state = RX_IDLE;
reg [5:0] rx_countdown;
reg [3:0] rx_bits_remaining;
reg [7:0] rx_data_;

reg tx_out = 1'b1;
reg [1:0] tx_state = TX_IDLE;
reg [5:0] tx_countdown;
reg [3:0] tx_bits_remaining;
reg [7:0] tx_data_;

assign valid = (recv_state == RX_RECEIVED);
assign rx_data = rx_data_;
assign tx = tx_out;
assign busy = (tx_state != TX_IDLE);

always @(posedge clk) begin
  if (!resetq) begin
    recv_state <= RX_IDLE;
    tx_state <= TX_IDLE;
  end else begin
    rx_clk_divider <= rx_clk_divider - 11'd1;
    if (rx_clk_divider == 0) begin
      rx_clk_divider <= CLOCK_DIVIDE;
      rx_countdown <= rx_countdown - 6'd1;
    end
    tx_clk_divider <= tx_clk_divider - 11'd1;
    if (tx_clk_divider == 0) begin
      tx_clk_divider <= CLOCK_DIVIDE;
      tx_countdown <= tx_countdown - 6'd1;
    end

    case (recv_state)
      RX_IDLE: begin
        if (!rx) begin
          rx_clk_divider <= CLOCK_DIVIDE;
          rx_countdown <= 6'd2;
          recv_state <= RX_CHECK_START;
        end
      end

      RX_CHECK_START: begin
        if (rx_countdown == 0) begin
          if (!rx) begin
            rx_countdown <= 6'd4;
            rx_bits_remaining <= 4'd8;
            recv_state <= RX_READ_BITS;
          end else begin
            recv_state <= RX_ERROR;
          end
        end
      end

      RX_READ_BITS: begin
        if (rx_countdown == 0) begin
          rx_data_ <= {rx, rx_data_[7:1]};
          rx_countdown <= 6'd4;
          rx_bits_remaining <= rx_bits_remaining - 4'd1;
          recv_state <= (rx_bits_remaining ? RX_READ_BITS : RX_CHECK_STOP);
        end
      end

      RX_CHECK_STOP: begin
        if (rx_countdown == 0) begin
          recv_state <= (rx ? RX_RECEIVED : RX_ERROR);
        end
      end

      RX_DELAY_RESTART: begin
        recv_state <= (rx_countdown ? RX_DELAY_RESTART : RX_IDLE);
      end

      RX_ERROR: begin
        rx_countdown <= 6'd8;
        recv_state <= RX_DELAY_RESTART;
      end

      RX_RECEIVED: begin
        if (rd) begin
          recv_state <= RX_IDLE;
        end
      end
    endcase

    case (tx_state)
      TX_IDLE: begin
        if (wr) begin
          tx_data_ <= tx_data;
          tx_clk_divider <= CLOCK_DIVIDE;
          tx_countdown <= 6'd4;
          tx_out <= 1'b0;
          tx_bits_remaining <= 4'd8;
          tx_state <= TX_SENDING;
        end
      end

      TX_SENDING: begin
        if (tx_countdown == 0) begin
          if (tx_bits_remaining) begin
            tx_bits_remaining <= tx_bits_remaining - 4'd1;
            tx_out <= tx_data_[0];
            tx_data_ <= {1'b0, tx_data_[7:1]};
            tx_countdown <= 6'd4;
            tx_state <= TX_SENDING;
          end else begin
            tx_out <= 1'b1;
            tx_countdown <= 6'd8;
            tx_state <= TX_DELAY_RESTART;
          end
        end
      end

      TX_DELAY_RESTART: begin
        tx_state <= (tx_countdown ? TX_DELAY_RESTART : TX_IDLE);
      end
    endcase
  end
end

endmodule

