            state <= STATE_IDLE;
            interrupt <= 0;
            error <= 0;
            file_num <= 0;
            file_write <= 0;
            file_read <= 0;
            file_write_data <= 0;
            sample_count <= 0;
            file_data_in <= 0;
            equation_done <= 0;
            dsp_output0_reg <= 0;
            dsp_output1_reg <= 0;
            dsp_output2_reg <= 0;
            dsp_output3_reg <= 0;
            dsp_output4_reg <= 0;
            operand0 <= 0;
        end else begin
            case (state)
                STATE_IDLE: begin
                    file_num <= input_file0;
                    file_write <= 0;
                    file_read <= 0;
                    equation_done <= 0;
                    if (equation_start) begin
                        file_write_data <= 0;
                        dsp_output0_reg <= 0;
                        dsp_output1_reg <= 0;
                        dsp_output2_reg <= 0;
                        dsp_output3_reg <= 0;
                        dsp_output4_reg <= 0;
