module rtlpp_01681 (
    input clk,
    input rst,
    input rx,
    output tx,
    input transmit,
    input [7:0] tx_byte,
    output reg received,
    output [7:0] rx_byte,
    output reg is_receiving,
    output reg is_transmitting,
    output reg recv_error
);
    parameter CLOCK_DIVIDE = 313;

    localparam RX_IDLE = 3'd0;
    localparam RX_CHECK_START = 3'd1;
    localparam RX_READ_BITS = 3'd2;
    localparam RX_CHECK_STOP = 3'd3;
    localparam RX_DELAY_RESTART = 3'd4;
    localparam RX_ERROR = 3'd5;
    localparam RX_RECEIVED = 3'd6;

    localparam TX_IDLE = 2'd0;
    localparam TX_SENDING = 2'd1;
    localparam TX_DELAY_RESTART = 2'd2;

    reg [10:0] rx_clk_divider = CLOCK_DIVIDE;
    reg [10:0] tx_clk_divider = CLOCK_DIVIDE;

    reg [2:0] recv_state = RX_IDLE;
    reg [5:0] rx_countdown;
    reg [3:0] rx_bits_remaining;
    reg [7:0] rx_data = 0;

    reg tx_out = 1'b1;
    reg [1:0] tx_state = TX_IDLE;
    reg [5:0] tx_countdown;
    reg [3:0] tx_bits_remaining;
    reg [7:0] tx_data;

    assign rx_byte = rx_data;
    assign tx = tx_out;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            recv_state <= RX_IDLE;
            tx_state <= TX_IDLE;
            rx_clk_divider <= CLOCK_DIVIDE;
            tx_clk_divider <= CLOCK_DIVIDE;
            received <= 0;
            recv_error <= 0;
            is_receiving <= 0;
            is_transmitting <= 0;
            tx_out <= 1'b1;
        end else begin
            rx_clk_divider <= rx_clk_divider - 1;
            if (rx_clk_divider == 0) begin
                rx_clk_divider <= CLOCK_DIVIDE;
                rx_countdown <= rx_countdown - 1;
            end
            tx_clk_divider <= tx_clk_divider - 1;
            if (tx_clk_divider == 0) begin
                tx_clk_divider <= CLOCK_DIVIDE;
                tx_countdown <= tx_countdown - 1;
            end

            case (recv_state)
                RX_IDLE: begin
                    if (!rx) begin
                        rx_clk_divider <= CLOCK_DIVIDE;
                        rx_countdown <= 2;
                        recv_state <= RX_CHECK_START;
                    end
                end
                RX_CHECK_START: begin
                    if (rx_countdown == 0) begin
                        if (!rx) begin
                            rx_countdown <= 4;
                            rx_bits_remaining <= 8;
                            recv_state <= RX_READ_BITS;
                        end else begin
                            recv_state <= RX_ERROR;
                        end
                    end
                end
                RX_READ_BITS: begin
                    if (rx_countdown == 0) begin
                        rx_data <= {rx, rx_data[7:1]};
                        rx_countdown <= 4;
                        rx_bits_remaining <= rx_bits_remaining - 1;
                        recv_state <= rx_bits_remaining ? RX_READ_BITS : RX_CHECK_STOP;
                    end
                end
                RX_CHECK_STOP: begin
                    if (rx_countdown == 0) begin
                        recv_state <= rx ? RX_RECEIVED : RX_ERROR;
                    end
                end
                RX_DELAY_RESTART: begin
                    recv_state <= rx_countdown ? RX_DELAY_RESTART : RX_IDLE;
                end
                RX_ERROR: begin
                    rx_countdown <= 8;
                    recv_state <= RX_DELAY_RESTART;
                end
                RX_RECEIVED: begin
                    recv_state <= RX_IDLE;
                end
            endcase

            case (tx_state)
                TX_IDLE: begin
                    if (transmit) begin
                        tx_data <= tx_byte;
                        tx_clk_divider <= CLOCK_DIVIDE;
                        tx_countdown <= 4;
                        tx_out <= 0;
                        tx_bits_remaining <= 8;
                        tx_state <= TX_SENDING;
                    end
                end
                TX_SENDING: begin
                    if (tx_countdown == 0) begin
                        if (tx_bits_remaining) begin
                            tx_bits_remaining <= tx_bits_remaining - 1;
                            tx_out <= tx_data[0];
                            tx_data <= {1'b0, tx_data[7:1]};
                            tx_countdown <= 4;
                            tx_state <= TX_SENDING;
                        end else begin
                            tx_out <= 1;
                            tx_countdown <= 8;
                            tx_state <= TX_DELAY_RESTART;
                        end
                    end
                end
                TX_DELAY_RESTART: begin
                    tx_state <= tx_countdown ? TX_DELAY_RESTART : TX_IDLE;
                end
            endcase
        end

        received <= (recv_state == RX_RECEIVED);
        recv_error <= (recv_state == RX_ERROR);
