module rtlpp_11061 (
    address,
    begintransfer,
    clk,
    reset_n,
    write,
    writedata,
    readdata
);

  output reg [31:0] readdata;
  input      [ 3:0] address;
  input             begintransfer;
  input             clk;
  input             reset_n;
  input             write;
  input      [31:0] writedata;

  wire              clk_en;
  reg       [63:0]  event_counter_0;
  reg       [63:0]  event_counter_1;
  reg       [63:0]  event_counter_2;
  reg       [63:0]  event_counter_3;
  wire              global_enable;
  wire              global_reset;
  wire              go_strobe_0;
  wire              go_strobe_1;
  wire              go_strobe_2;
  wire              go_strobe_3;
