module ram_block (
    input wire [31:0] portadatain,
    input wire [7:0] portaaddr,
    input wire portawe,
    input wire portare,
    input wire [31:0] portbdatain,
    input wire [7:0] portbaddr,
    input wire portbwe,
    input wire portbre,
    input wire clk0,
    input wire clk1,
    input wire ena0,
    input wire ena1,
    input wire ena2,
    input wire ena3,
    input wire clr0,
    input wire clr1,
    input wire portabyteenamasks,
    input wire portbbyteenamasks,
    input wire portaaddrstall,
    input wire portbaddrstall,
    input wire devclrn,
    input wire devpor,
    input wire portacontrol,
    input wire portbcontrol,
    output reg [31:0] portadataout,
    output reg [31:0] portbdataout
);

    // RAM implementation
    reg [31:0] mem [0:255];

    always @(posedge clk0) begin
        if (portawe) begin
            mem[portaaddr] <= portadatain;
        end
        if (portare) begin
            portadataout <= mem[portaaddr];
        end
    end

    always @(posedge clk1) begin
        if (portbwe) begin
            mem[portbaddr] <= portbdatain;
        end
        if (portbre) begin
            portbdataout <= mem[portbaddr];
        end
    end

endmodule

files.conformal_rtl_origen_136237.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

