);

reg [7:0] bus_capture_reg;

always @(posedge clk) begin
    if (rst) begin
        bus_capture_reg <= 8'h00;
    end
    else if (databus == rx_data) begin
        bus_capture_reg <= databus;
    end
end

assign bus_capture = bus_capture_reg;

always @(*) begin
    if (iocs && iorw) begin
        case (ioaddr)
