module fp_sub #(
    parameter WIDTH = 32
) (
    input [WIDTH-1:0] a,
    input [WIDTH-1:0] b,
    output [WIDTH-1:0] result
);
    assign result = a - b;
endmodule

module fp_div #(
    parameter WIDTH = 32
) (
    input [WIDTH-1:0] a,
    input [WIDTH-1:0] b,
    output reg [WIDTH-1:0] result
);
    reg [WIDTH-1:0] abs_a, abs_b;
    reg sign;

    always @* begin
        abs_a = a[WIDTH-1] ? -a : a;
        abs_b = b[WIDTH-1] ? -b : b;
        sign = a[WIDTH-1] ^ b[WIDTH-1];
        result = sign ? -(abs_a / abs_b) : (abs_a / abs_b);
    end
endmodule

