    reg [DATAW-1:0] head_ptr;
    reg [DATAW-1:0] tail_ptr;
    reg [DATAW-1:0] fifo_count;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            head_ptr <= 0;
