        end else begin
            // FIFO write operation
            if (ififo_wen && ififo_rdy) begin
                mem[tail_ptr] <= ififo_wdata;
                mem_strb[tail_ptr] <= 0; // Update as per your requirement
                mem_keep[tail_ptr] <= 0; // Update as per your requirement
