module origen_154797 #(
    parameter LCD_WIDTH = 800,
    parameter LCD_HEIGHT = 600,
    parameter BALL_SLOW = 10,
    parameter BALL_SIZE = 8,
    parameter RACKET_SIZE = 80,
    parameter RACKET_Y_SLOW = 5
)(
